var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"며칠 전, 로터스 아마니 밸리.","JPN":"数日前、ロータスアマニーバレー。","ENG":"A few days ago, Lotus, Amani Valley.","TWN":"幾天前，洛德斯阿瑪尼山谷。","DEU":"A few days ago, Lotus, Amani Valley.","FRA":"A few days ago, Lotus, Amani Valley."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"으으… 좋은 냄새…","JPN":"うう……いい匂い……","ENG":"Mm... It smells so good...","TWN":"呃呃…味道好香…"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"한 팩만 달라고 하면 분명 신고 당하겠지?","JPN":"1パックだけほしいって言ったら、通報されるかな？","ENG":"I'll get reported if I ask for a pack, right?","TWN":"只要一包的話肯定會被檢舉吧？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…팔 하나 잘라볼까? 응급 환자인 척 쓰러지면 수혈이라도 해주지 않으려나?","JPN":"……腕を切ってみようかな？　緊急患者のふりをして倒れたら、輸血してもらえたりして……","ENG":"...Maybe I should cut off an arm? Won't they give me a blood transfusion if I pretend to be an emergency patient?","TWN":"…要不要砍斷一隻手臂？裝作是急救患者昏倒的話，他們會幫忙輸血嗎？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"감시원들 눈을 피해 무슨 음모를 꾸미나 했더니…","JPN":"監視の目を逃れて何を企んでいるのかと思えば……","ENG":"I was wondering what you were up to avoiding the guards' eyes, but...","TWN":"我還在想妳會避開監視人員的視線，策畫什麼陰謀…"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"대로변에 숨어 자해공갈을 계획하고 있을 줄은 몰랐군요.","JPN":"道端に隠れて自害作戦を立てていたとは心外ですね。","ENG":"I didn't expect you to be hiding on the side of the road, plotting to hurt yourself.","TWN":"沒想到妳居然躲在大馬路邊計畫自殘恐嚇。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"앗… 관리국 깡패…!","JPN":"あっ、管理局のごろつき……！","ENG":"Huh...?! The Administration gangster...!","TWN":"啊…管理局流氓…！"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"전 깡패가 아닙니다.","JPN":"私はごろつきではありません。","ENG":"I am not a gangster.","TWN":"我不是流氓。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"거짓말! 처음 만났을 때부터 날 피냐타처럼 때려 놓고선!","JPN":"嘘！　初めて会った時だって私をピニャータみたに叩き潰したくせに！","ENG":"Liar! You beat me up like a piñata when we first met!","TWN":"騙人！你從第一次見面就把我當皮納塔一樣打了一頓！"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시니어 소집 회담 때를 말하는 겁니까?","JPN":"シニア召集会談の時の話ですか？","ENG":"Are you talking about the Senior convention meeting?","TWN":"妳指的是Senior召集會談的時候嗎？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"전 당신이 여직원의 목덜미를 노리고 이빨을 드러내기에 제지했을 뿐입니다.","JPN":"私はあなたが牙を剥いて、女性社員の首元を狙おうとしたから阻止しただけです。","ENG":"I only stopped you because you showed your teeth and tried to bite the back of a female employee's neck.","TWN":"我只不過是阻止妳覬覦女員工的脖子露出牙齒而已。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그때는 이상한 변태라고만 생각했는데… 과거의 사정을 알고 나니 명백한 흡혈 시도였군요.","JPN":"あの時はただの変態だと思いましたが……あれは意図した吸血のための行動だったのですね。","ENG":"At the time, I thought you were just a pervert, but... now that I think back on it, you were trying to suck on her blood.","TWN":"我當時只以為妳是個奇怪的變態…但知道過去的事情之後，原來那是明擺著試圖吸血啊。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그, 그땐 마스크를 잃어버려서 그랬어요!","JPN":"あ、あの時はマスクをなくしたから仕方なかったんです！","ENG":"I-it's because I lost my mask back then!","TWN":"那、那時候是因為我把口罩弄丟了！"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"냄새 때문에 아찔해지긴 했지만, 그래도 물지는 않았다고요!","JPN":"匂いのせいで一瞬意識が飛んだけど、噛まずに済んだじゃないですか！","ENG":"The smell made me a little dizzy, but I didn't bite!","TWN":"雖然的確因為味道變得暈頭轉向，但我還是沒咬人！"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"동물 피 같은 걸론 해소할 수 없는 겁니까?","JPN":"あの衝動は動物の血では解消できないのですか？","ENG":"Can't you satiate yourself with animal blood?","TWN":"不能用動物血之類的東西消除嗎？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"하, 그야 안되죠. 절 짐승쯤으로 여기는 건가요?","JPN":"当たり前でしょう。私を獣扱いしないでくれますか？","ENG":"*Sigh* Nope. Do you think I'm an animal or something?","TWN":"哈，當然不行，難道你把我當成禽獸嗎？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"인간 피를 노리는 쪽도 짐승인 건 매한가지라 생각합니다만.","JPN":"人間の血を狙っている時点で獣と変わらないと思いますが。","ENG":"You're not less of an animal to be seeking human blood, though.","TWN":"雖然我認為覬覦人血也和禽獸沒有兩樣。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"따라오시죠. 시니어님 방에 응급용 혈액팩을 비축해둔 게 좀 있습니다.","JPN":"ついてきてください。シニアの部屋に、保存しておいた緊急用の血液パックが少しあります。","ENG":"Follow me. There should be some emergency blood packs stored in the Senior's office.","TWN":"跟我來吧，Senior房間裡有一些應急用的血袋。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"진짜요? 앗싸!","JPN":"本当ですか？　やったー！","ENG":"Really? Awesome!","TWN":"真的嗎？好耶！"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그런데, 저 벌 주려고 온 거 아니었어요? 당연히 감옥에 갇힐 줄 알았는데.","JPN":"でも、私を懲らしめるために来たのでは？　牢に放り込まれると思ってたのに。","ENG":"But didn't you come to find and punish me? I thought you were throwing me in jail.","TWN":"不過，你不是來懲罰我的嗎？我還以為自己當然會被關進監獄。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"당장 그럴 일은 없을 겁니다.","JPN":"すぐにはしません。","ENG":"That won't be happening, at least, not right now.","TWN":"暫時不會發生那種事。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"진심? 저 그럼 자유에요?","JPN":"本当？　じゃあ私って自由ですか？","ENG":"Seriously? Then, I'm free?","TWN":"真的？那我是自由的嗎？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"진실을 캐묻기 위한 잔혹한 고문… 같은 것도 안 당하나요?","JPN":"真実を吐き出させるための残酷な拷問……とかもないですか？","ENG":"You're not even going to... torture me for the truth?","TWN":"也不會遭受為了追查真相的殘酷拷問…之類的事嗎？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"왜 그 부분에서 아쉬워하는진 모르겠습니다만…","JPN":"なぜ残念そうな顔をするのか理解できませんが……","ENG":"I don't know what you are expecting, but...","TWN":"雖然不知道妳為什麼要對這部分感到可惜…"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"당신의 처분은 잠시 유예됐을 뿐입니다. 당신의 죄를 입증할 주요인물이 실종된 상태니까요.","JPN":"あなたの処分については、決定が少し猶予されただけです。あなたの罪を証明できる主要人物が行方不明なので。","ENG":"Your disposition has only been temporarily postponed. Because the key person who can prove your crime is missing at the moment.","TWN":"但妳的處分只是暫緩而已，因為能證實妳罪行的主要人物失蹤了。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"아…","JPN":"あ……","ENG":"Ah...","TWN":"啊…"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그리고 관리국에선 실종된 시니어를 찾는데 당신이 도움이 될 것이라 판단했습니다.","JPN":"そして、管理局は行方不明のシニアを探すために、あなたの力が役に立つと判断しました。","ENG":"Also, the Administration has decided that you will be of help in searching for the missing Senior.","TWN":"而且管理局判斷妳會對尋找失蹤的Senior有幫助。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"오늘처럼 멋대로 사라지지만 않는다면 말이죠.","JPN":"今日みたいに勝手にいなくならない限り、です。","ENG":"Only if you don't randomly disappear like you did today, that is.","TWN":"只要別像今天一樣自顧自地消失不見就好。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"네! 잭슨 씨를 찾을 수만 있다면, 저 완전 협조할게요!","JPN":"はい！　ジャクソンさんを見つけるためなら何でも協力します！","ENG":"Okay! If we can find Mr. Jackson, then I'm all in!","TWN":"好！只要能找到傑森，我會全力幫忙！"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"……그렇게 말해서, 믿었는데.","JPN":"……って言われたから信じたのに。","ENG":"...That's what you said, and I believed you.","TWN":"……他這樣說，我就相信了。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"날 속였어! 전 빠는 쪽이지, 빨리는 쪽이 아니라고요!","JPN":"騙された！　私は吸われるほうじゃなくて吸うほうなんだってば！","ENG":"You tricked me! I'm the one who sucks blood, not the other way around!","TWN":"結果他騙了我！我是吸血，而不是被吸血的一方！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"L33_1","slots":{"L":null,"C":null,"R":{"char_id":"L18_1","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"L24_1","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"L24_1","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};